const Importer = {
  parse(text) {
    let doc;
    try { doc = jsyaml.load(text); } catch (e) { return { error: 'YAML parse failed: ' + e.message }; }
    if (!doc || typeof doc !== 'object') return { error: 'No YAML mapping found' };
    const cams = doc.cameras ? Object.entries(doc.cameras) : [['(snippet)', doc]];
    const out = { cameras: [], warnings: [] };
    for (const [name, cfg] of cams) {
      const cam = { name, zones: [], motionMasks: [], objectMasks: [] };
      for (const [zName, z] of Object.entries(cfg?.zones || {}))
        cam.zones.push({ name: zName, coords: this._coords(z.coordinates, out.warnings, zName) });
      for (const m of this._asList(cfg?.motion?.mask))
        cam.motionMasks.push({ coords: this._coords(m, out.warnings, 'motion mask') });
      for (const [oType, f] of Object.entries(cfg?.objects?.filters || {}))
        for (const m of this._asList(f?.mask))
          cam.objectMasks.push({ objectType: oType, coords: this._coords(m, out.warnings, oType + ' mask') });
      if (cam.zones.length || cam.motionMasks.length || cam.objectMasks.length) out.cameras.push(cam);
    }
    if (!out.cameras.length) return { error: 'No zones or masks found under cameras.*, zones, motion.mask, or objects.filters' };
    return out;
  },
  _asList(v) { return v == null ? [] : Array.isArray(v) ? v : [v]; },
  _coords(v, warnings, label) {
    const nums = String(v ?? '').split(',').map(Number);
    if (nums.length < 6 || nums.length % 2 || nums.some(isNaN)) { warnings.push(`Skipped ${label}: malformed coordinates`); return null; }
    const pts = []; for (let i = 0; i < nums.length; i += 2) pts.push({ x: nums[i], y: nums[i + 1] });
    return { points: pts, pixelSpace: nums.some(n => n > 1.001) };
  }
};
